import React from 'react';

function Toolbox({ data }) {
  if (!data || data.length === 0) return null;

  return (
    <section id="toolbox" className="py-12 md:py-16 bg-white">
      <div className="max-w-7xl mx-auto px-4">
        <p className="text-xs uppercase tracking-widest text-gray-500 font-semibold mb-4">
          Working System
        </p>
        <h2 className="text-5xl font-black text-gray-900 mb-12">Toolbox</h2>

        <div className="grid grid-cols-2 md:grid-cols-4 lg:grid-cols-7 gap-6">
          {data.map((tool) => (
            <div
              key={tool.id}
              className="flex flex-col items-center text-center group cursor-pointer"
            >
              {/* Tool Icon */}
              <div className="w-20 h-20 md:w-24 md:h-24 flex items-center justify-center mb-4 text-5xl md:text-6xl group-hover:scale-110 transition-transform duration-300">
                {tool.icon}
              </div>
              
              {/* Tool Name */}
              <p className="text-sm md:text-base font-semibold text-gray-900 group-hover:text-gray-600 transition-colors">
                {tool.name}
              </p>
            </div>
          ))}
        </div>
      </div>
    </section>
  );
}

export default Toolbox;
